import{_ as t,c as i,o as a,aj as s}from"./chunks/framework.HLg5PcC2.js";const g=JSON.parse('{"title":"Starting with the Template App","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/template-app.md","filePath":"getting-started/template-app.md"}'),n={name:"getting-started/template-app.md"};function o(l,e,r,p,h,d){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="starting-with-the-template-app" tabindex="-1">Starting with the Template App <a class="header-anchor" href="#starting-with-the-template-app" aria-label="Permalink to “Starting with the Template App”">​</a></h1><p>The fastest way to build an app on Primitive is to start from the official template. This guide walks you through creating a new project, configuring authentication, and running your first app.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h2><ul><li><strong>Node.js 18+</strong> with pnpm installed</li><li><strong>GitHub account</strong> with access to <a href="https://github.com/Primitive-Labs/primitive-app-template" target="_blank" rel="noreferrer">Primitive-Labs/primitive-app-template</a></li></ul><h3 id="installing-pnpm" tabindex="-1">Installing pnpm <a class="header-anchor" href="#installing-pnpm" aria-label="Permalink to “Installing pnpm”">​</a></h3><p>If you don&#39;t have pnpm installed, the easiest way is through Corepack (included with Node.js 16+):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prepare</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pnpm@latest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --activate</span></span></code></pre></div><p>Alternatively, see the <a href="https://pnpm.io/installation" target="_blank" rel="noreferrer">pnpm installation guide</a> for other methods.</p><h2 id="create-your-repository" tabindex="-1">Create Your Repository <a class="header-anchor" href="#create-your-repository" aria-label="Permalink to “Create Your Repository”">​</a></h2><ol><li>Go to <a href="https://github.com/Primitive-Labs/primitive-app-template" target="_blank" rel="noreferrer">primitive-app-template</a> on GitHub</li><li>Click the green <strong>&quot;Use this template&quot;</strong> button in the upper right</li><li>Choose a name for your new repository and create it</li></ol><p>Then clone your new repo:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/your-username/my-app.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h2 id="configure-google-oauth" tabindex="-1">Configure Google OAuth <a class="header-anchor" href="#configure-google-oauth" aria-label="Permalink to “Configure Google OAuth”">​</a></h2><p>Your app will use Google for authentication. You&#39;ll need to create OAuth credentials:</p><ol><li>Go to the <a href="https://console.cloud.google.com/auth/clients" target="_blank" rel="noreferrer">Google Cloud Console OAuth page</a></li><li>Create a new OAuth client (Web application type)</li><li>Add these settings:</li></ol><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Authorized JavaScript origins</td><td><code>http://localhost:5173</code></td></tr><tr><td>Authorized redirect URIs</td><td><code>http://localhost:5173/oauth/callback</code></td></tr></tbody></table><ol start="4"><li>Save and note your <strong>Client ID</strong> and <strong>Client Secret</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">Production Setup</p><p>When deploying to production, you&#39;ll add your production domain to these settings alongside localhost.</p></div><h2 id="create-your-app-on-primitive" tabindex="-1">Create Your App on Primitive <a class="header-anchor" href="#create-your-app-on-primitive" aria-label="Permalink to “Create Your App on Primitive”">​</a></h2><ol><li>Go to the <a href="https://admin.primitiveapi.com/login" target="_blank" rel="noreferrer">Primitive Admin Console</a></li><li>Sign in with Google</li><li>Click <strong>Create New App</strong></li><li>Enter your app details: <ul><li><strong>App Name</strong>: Your app&#39;s display name</li><li><strong>Google Client ID</strong>: From the previous step</li><li><strong>Google Client Secret</strong>: From the previous step</li></ul></li><li>Under <strong>Allowed Origins</strong>, add <code>http://localhost:5173</code></li><li>Save and note your <strong>App ID</strong></li></ol><h2 id="configure-your-environment" tabindex="-1">Configure Your Environment <a class="header-anchor" href="#configure-your-environment" aria-label="Permalink to “Configure Your Environment”">​</a></h2><p>Open the <code>.env</code> file in your project and update the App ID:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VITE_APP_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-app-id-here</span></span></code></pre></div><h2 id="run-your-app" tabindex="-1">Run Your App <a class="header-anchor" href="#run-your-app" aria-label="Permalink to “Run Your App”">​</a></h2><p>Start the development server:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>Open <code>http://localhost:5173</code> in your browser. You should see your app&#39;s login screen. Sign in with Google to access the app.</p><p><strong>Congratulations!</strong> You now have a working Primitive app with:</p><ul><li>Google authentication</li><li>Real-time data sync</li><li>Offline support</li><li>A Vue + TypeScript + Tailwind foundation</li></ul><h2 id="why-vue" tabindex="-1">Why Vue? <a class="header-anchor" href="#why-vue" aria-label="Permalink to “Why Vue?”">​</a></h2><p>The template uses Vue 3 because it produces cleaner, more maintainable code—especially when working with AI coding assistants. Vue&#39;s straightforward reactivity model avoids the complexity of patterns like React&#39;s <code>useEffect</code> chains.</p><div class="tip custom-block"><p class="custom-block-title">Using Other Frameworks</p><p>The core libraries—<strong>js-bao</strong> and <strong>js-bao-wss-client</strong>—are plain JavaScript and work with any framework. If you prefer React, Svelte, Solid, or vanilla JS, you can use these libraries directly. You&#39;ll just need to handle the framework integration yourself rather than using our Vue-specific <code>primitive-app</code> helpers.</p></div><h2 id="what-s-in-the-template" tabindex="-1">What&#39;s in the Template? <a class="header-anchor" href="#what-s-in-the-template" aria-label="Permalink to “What&#39;s in the Template?”">​</a></h2><p>The template gives you a production-ready starting point:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>my-app/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── components/     # Vue components</span></span>
<span class="line"><span>│   ├── config/         # App configuration</span></span>
<span class="line"><span>│   ├── layouts/        # Page layouts</span></span>
<span class="line"><span>│   ├── lib/            # Business logic</span></span>
<span class="line"><span>│   ├── models/         # js-bao data models</span></span>
<span class="line"><span>│   ├── pages/          # Route components</span></span>
<span class="line"><span>│   └── router/         # Vue Router setup</span></span>
<span class="line"><span>├── .env                # Environment variables</span></span>
<span class="line"><span>└── wrangler.toml       # Cloudflare deployment config</span></span></code></pre></div><p>Key configuration files:</p><ul><li><strong><code>src/config/appConfig.ts</code></strong> — App name, document mode, navigation</li><li><strong><code>src/config/envConfig.ts</code></strong> — API URLs, App ID, logging</li><li><strong><code>src/models/</code></strong> — Your data models (start here!)</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><p>Now that your app is running:</p><ol><li><strong><a href="./local-first-model.html">The Local-First Model</a></strong> — Understand how Primitive apps work</li><li><strong><a href="./understanding-documents.html">Understanding Documents</a></strong> — Learn about documents and sharing</li><li><strong><a href="./working-with-data.html">Working with Data</a></strong> — Create your first data models</li></ol><h2 id="deploying-to-production" tabindex="-1">Deploying to Production <a class="header-anchor" href="#deploying-to-production" aria-label="Permalink to “Deploying to Production”">​</a></h2><p>When you&#39;re ready to deploy, the template includes configuration for Cloudflare Workers. See the template&#39;s README for detailed deployment instructions covering:</p><ul><li>Setting up production environment variables</li><li>Configuring <code>wrangler.toml</code></li><li>Building and deploying with <code>wrangler deploy</code></li></ul>`,43)])])}const u=t(n,[["render",o]]);export{g as __pageData,u as default};
